const electivas = $input.all();
const resultado = [];

electivas.forEach(item => {
  const electiva = { ...item.json };

  delete electiva.descripcion;

  if (electiva.horario && typeof electiva.horario === 'string') {
    try {
      const horarioObj = JSON.parse(electiva.horario);

      if (horarioObj.sesiones && Array.isArray(horarioObj.sesiones)) {
        horarioObj.sesiones = horarioObj.sesiones.map(sesion => {
          if (sesion.salon && typeof sesion.salon === 'string') {
            sesion.salon = sesion.salon.trim().replace(/\s+\w$/, '').trim();
          }
          return sesion;
        });
      }

      electiva.horario = JSON.stringify(horarioObj);
    } catch (e) {
      // Mantener horario original si falla
    }
  }

  resultado.push({ json: electiva });
});

return resultado;

const items = $input.all();
const resultado = [];

items.forEach(item => {
    const tipo = item.json.tipo;
    const codigo = item.json.codigo;
    const datos = item.json.datos;

    if (Array.isArray(datos) && datos.length > 0) {
        datos.forEach(elemento => {
            resultado.push({
                json: {
                    tipo: tipo,
                    ...elemento
                }
            });
        });
    }
});

return resultado;

const electivas = $('Limpiar Salon Horarios').all();
const resultado = [];

electivas.forEach(item => {
  const codigo = item.json.codigo;
  const nrc = item.json.nrc;  // ← CAMBIO 1: Agregar esta línea

  let horariosParsed = [];
  if (item.json.horario) {
    try {
      const horarioObj = typeof item.json.horario === 'string' 
        ? JSON.parse(item.json.horario) 
        : item.json.horario;

      if (horarioObj.sesiones && Array.isArray(horarioObj.sesiones)) {
        horariosParsed = horarioObj.sesiones.map(sesion => ({
          electiva_nrc: nrc,  // ← CAMBIO 2: codigo → nrc
          dia: sesion.dia || null,
          hora_inicio: sesion.hora_inicio || null,
          hora_fin: sesion.hora_fin || null,
          salon: sesion.salon || null
        }));
      }
    } catch (e) {}
  }

  let profesoresParsed = [];
  if (item.json.profesores) {
    try {
      const profesoresObj = typeof item.json.profesores === 'string' 
        ? JSON.parse(item.json.profesores) 
        : item.json.profesores;

      if (profesoresObj.lista && Array.isArray(profesoresObj.lista)) {
        profesoresParsed = profesoresObj.lista.map(profesor => ({
          electiva_nrc: nrc,  // ← CAMBIO 3: codigo → nrc
          nombre: profesor.nombre || null,
          semana_inicio: profesor.semana_inicio || null,  // ← CAMBIO 4: Agregar
          semana_fin: profesor.semana_fin || null  // ← CAMBIO 5: Agregar
        }));
      }
    } catch (e) {}
  }

  resultado.push({
    json: {
      tipo: 'profesores',
      codigo: codigo,
      datos: profesoresParsed
    }
  });

  resultado.push({
    json: {
      tipo: 'horarios',
      codigo: codigo,
      datos: horariosParsed
    }
  });
});

return resultado;
